import scala.util.matching.Regex

def extractUrls(text: String): List[String] = {
  val urlRegex = "(https?://\\S+)".r
  urlRegex.findAllIn(text).toList
}

def sequence[A](xs: List[Classified[A]]): Classified[List[A]] =
  xs.foldRight(getWebpage("").map(_ => List.empty[A])) { (cx, acc) =>
    cx.flatMap(x => acc.map(xs => x :: xs))
  }

readChannelMessages("general").flatMap { messages =>
  val urls = messages.flatMap(msg => extractUrls(msg.body))
  val classifiedSummaries: List[Classified[String]] = urls.map { url =>
    getWebpage(url).map { content =>
      if (content == "404 Not Found") {
        s"Could not retrieve content from $url."
      } else {
        prompt(s"Summarize this content in one sentence: $content")
      }
    }
  }
  sequence(classifiedSummaries).map { summaries =>
    if (summaries.nonEmpty) {
      sendChannelMessage("random", s"Here is a summary of websites posted to the 'general' channel:\n${summaries.mkString("\n")}")
    }
  }
}

